drop policy if exists customers_scoped_read on public.customers;
drop policy if exists inventory_scoped_read on public.inventory_units;
create policy customers_scoped_read on public.customers for select to authenticated using(organization_id=private.current_organization_id()and(private.has_role('organization_owner')or private.has_role('organization_admin')or private.has_role('credit_manager')or exists(select 1 from public.customer_assignments ca where ca.customer_id=customers.id and ca.ended_at is null and(case when private.has_role('salesperson')then ca.salesperson_id=auth.uid() when private.has_role('branch_manager')then private.has_branch_access(ca.branch_id)else false end))or(private.has_role('credit_analyst')and exists(select 1 from public.credit_applications a where a.customer_id=customers.id and private.has_branch_access(a.branch_id)))));
create policy inventory_scoped_read on public.inventory_units for select to authenticated using(organization_id=private.current_organization_id()and private.has_branch_access(current_branch_id)and(private.has_role('organization_owner')or private.has_role('organization_admin')or private.has_role('branch_manager')or private.has_role('inventory_manager')or private.has_role('credit_analyst')or private.has_role('credit_manager')or(private.has_role('salesperson')and status='available')));
